const client = $input.first().json;
const clientId = client.id;
const clientName = client.name;
const tier = client.risk_tier || 'conservative';
const portfolioValue = parseFloat(client.portfolio_value || 0);
const currentDrawdown = parseFloat(client.current_drawdown_pct || 0);
const openPositions = parseInt(client.open_positions || 0, 10);
const largestPositionPct = parseFloat(client.largest_position_pct || 0);
const dailyPnlPct = parseFloat(client.daily_pnl_pct || 0);

const limits = {
  conservative: { maxPositionPct: 2, maxDrawdown: 5, maxConcurrent: 5, maxSingleExposure: 25 },
  moderate:     { maxPositionPct: 5, maxDrawdown: 5, maxConcurrent: 10, maxSingleExposure: 25 },
  aggressive:   { maxPositionPct: 10, maxDrawdown: 5, maxConcurrent: 15, maxSingleExposure: 25 }
};

const tierLimits = limits[tier] || limits.conservative;
const breaches = [];

if (currentDrawdown > tierLimits.maxDrawdown) {
  breaches.push({ rule: 'max_drawdown', limit: tierLimits.maxDrawdown, actual: currentDrawdown, message: `Drawdown ${currentDrawdown}% exceeds ${tierLimits.maxDrawdown}% limit` });
}

if (openPositions > tierLimits.maxConcurrent) {
  breaches.push({ rule: 'max_concurrent_positions', limit: tierLimits.maxConcurrent, actual: openPositions, message: `${openPositions} open positions exceeds ${tierLimits.maxConcurrent} limit` });
}

if (largestPositionPct > tierLimits.maxSingleExposure) {
  breaches.push({ rule: 'max_single_exposure', limit: tierLimits.maxSingleExposure, actual: largestPositionPct, message: `Single position ${largestPositionPct}% exceeds ${tierLimits.maxSingleExposure}% limit` });
}

if (dailyPnlPct < -(tierLimits.maxDrawdown)) {
  breaches.push({ rule: 'daily_loss_limit', limit: tierLimits.maxDrawdown, actual: Math.abs(dailyPnlPct), message: `Daily loss ${Math.abs(dailyPnlPct)}% exceeds ${tierLimits.maxDrawdown}% limit` });
}

return [{
  json: {
    client_id: clientId,
    client_name: clientName,
    tier: tier,
    has_breach: breaches.length > 0,
    breach_count: breaches.length,
    breaches: breaches,
    checked_at: new Date().toISOString(),
    portfolio_value: portfolioValue,
    current_drawdown: currentDrawdown,
    open_positions: openPositions,
    largest_position_pct: largestPositionPct
  }
}];
